const companies = {};

for (const item of items) {
  const company = item.json["company name"]?.trim().toLowerCase() || "";

  if (!company) continue;

  // Only keep the first occurrence of each company
  if (!companies[company]) {
    companies[company] = item.json;
  }
}

const result = Object.values(companies).map(lead => ({ json: lead }));

return result;

